// Server-side validation — mirrors hospital-form/index.html
const body = $input.first().json.body || $input.first().json;

const FACILITY_TYPES = [
  'General Hospital',
  'Multi-specialty Clinic',
  'Dental Clinic',
  'Pathology Lab',
  'Diagnostic Center',
  'Physiotherapy Clinic',
  'Eye Clinic',
  'ENT Clinic',
  'Other Medical Facility',
];

const clean = (value, max = 1000) => String(value || '').trim().slice(0, max);
const hospital_name = clean(body.hospital_name, 200);
const facility_type = clean(body.facility_type, 80);
const address = clean(body.address, 1000);
const city = clean(body.city, 120);
const contact_phone = clean(body.contact_phone, 20).replace(/\s+/g, '');
const admin_contact_name = clean(body.admin_contact_name, 150);
const clinic_logo_url = clean(body.clinic_logo_url, 1000);
const clinic_email = clean(body.clinic_email, 254);
const clinic_website = clean(body.clinic_website, 1000);
const doctor_name = clean(body.doctor_name, 150);
const doctor_qualification = clean(body.doctor_qualification, 200);
const doctor_expertise = clean(body.doctor_expertise, 500);
const doctor_registration_number = clean(body.doctor_registration_number, 120);
const doctor_phone = clean(body.doctor_phone, 20).replace(/\s+/g, '');
const doctor_signature_url = clean(body.doctor_signature_url, 1000);
const consultation_hours = clean(body.consultation_hours, 200);

const errors = [];
const isUrl = value => /^https:\/\//i.test(value);


function rateLimitRequest(scope, key, limit, windowMs) {
  if (!key) return null;
  try {
    const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
    if (!store) return null;
    store._rateLimits = store._rateLimits || {};
    const now = Date.now();
    const bucketKey = scope + ':' + key;
    const bucket = Array.isArray(store._rateLimits[bucketKey]) ? store._rateLimits[bucketKey] : [];
    const recent = bucket.filter(ts => now - ts < windowMs);
    recent.push(now);
    store._rateLimits[bucketKey] = recent;
    return recent.length > limit ? Math.ceil((windowMs - (now - recent[0])) / 1000) : null;
  } catch (_) {
    return null;
  }
}

const headers = $input.first().json.headers || {};
const header = name => headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()] || '';
const clientIp = String(header('x-forwarded-for') || header('x-real-ip') || 'unknown').split(',')[0].trim();
const ipRetryAfter = rateLimitRequest('hospital-boarding-ip', clientIp, 40, 60 * 60 * 1000);
const phoneRetryAfter = contact_phone ? rateLimitRequest('hospital-boarding-contact', contact_phone, 6, 60 * 60 * 1000) : null;
if (ipRetryAfter || phoneRetryAfter) {
  errors.push('too_many_requests: please wait before submitting again');
}

if (!hospital_name || hospital_name.length < 2)
  errors.push('hospital_name: required, minimum 2 characters');

if (!FACILITY_TYPES.includes(facility_type))
  errors.push('facility_type: required, must be a supported facility type');

if (!address || address.length < 5)
  errors.push('address: required, minimum 5 characters');

if (!city || city.length < 2)
  errors.push('city: required, minimum 2 characters');

if (!/^\+?[1-9]\d{6,14}$/.test(contact_phone))
  errors.push('contact_phone: required, must be a valid phone number');

if (!admin_contact_name || admin_contact_name.length < 2)
  errors.push('admin_contact_name: required, minimum 2 characters');

if (clinic_logo_url && !isUrl(clinic_logo_url))
  errors.push('clinic_logo_url: must be an HTTPS URL');

if (clinic_email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(clinic_email))
  errors.push('clinic_email: must be a valid email address');

if (clinic_website && !isUrl(clinic_website))
  errors.push('clinic_website: must be an HTTPS URL');

if (!doctor_name || doctor_name.length < 2)
  errors.push('doctor_name: required, minimum 2 characters');

if (doctor_qualification && doctor_qualification.length < 2)
  errors.push('doctor_qualification: minimum 2 characters when provided');

if (!doctor_expertise || doctor_expertise.length < 2)
  errors.push('doctor_expertise: required, minimum 2 characters');

if (!doctor_registration_number || doctor_registration_number.length < 2)
  errors.push('doctor_registration_number: required, minimum 2 characters');

if (doctor_phone && !/^\+?[1-9]\d{6,14}$/.test(doctor_phone))
  errors.push('doctor_phone: must be a valid phone number');

if (doctor_signature_url && !isUrl(doctor_signature_url))
  errors.push('doctor_signature_url: must be an HTTPS URL');

if (!consultation_hours || consultation_hours.length < 2)
  errors.push('consultation_hours: required, minimum 2 characters');

if (errors.length > 0) {
  return [{ json: { _valid: false, _errors: errors } }];
}

return [{
  json: {
    _valid: true,
    _errors: [],
    hospital_name,
    facility_type,
    address,
    city,
    contact_phone,
    admin_contact_name,
    clinic_logo_url: clinic_logo_url || null,
    clinic_email: clinic_email || null,
    clinic_website: clinic_website || null,
    doctor_name,
    doctor_qualification: doctor_qualification || null,
    doctor_expertise,
    doctor_registration_number,
    doctor_phone: doctor_phone || null,
    doctor_signature_url: doctor_signature_url || null,
    consultation_hours,
  }
}];
